let currentRequestId=null;

document.addEventListener('click',function(e){
    let btn=e.target.closest('[data-view-request]');
    if(btn){
        currentRequestId = btn.dataset.viewRequest;

        fetch(`${API_URL}/requests/${currentRequestId}?_expand=client`)
        .then(r=>r.json())
        .then(rq=>{
            let box=document.querySelector('[data-screen="request-details"] .content');
            box.innerHTML=`
                <p><strong>Client:</strong> ${rq.client.name}</p>
                <p><strong>Car:</strong> ${rq.brand} ${rq.model}</p>
                <span class="badge">${rq.status}</span>
            `;
            showScreen('request-details');
        });
    }
});
